import{_ as t,o as r,c as a,ag as i}from"./chunks/framework.DXGyWiRo.js";const n="/images/lekt2101.jpg",s="/images/lekt2102.jpg",o="/images/lekt2103.jpg",u="/images/lekt2105.jpg",l="/images/lekt2104.jpg",g=JSON.parse('{"title":"Lektion 21","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion21.md","filePath":"lektionen/lektion21.md"}'),d={name:"lektionen/lektion21.md"};function m(p,e,b,h,c,k){return r(),a("div",null,[...e[0]||(e[0]=[i('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-21" tabindex="-1">Lektion 21 <a class="header-anchor" href="#lektion-21" aria-label="Permalink to &quot;Lektion 21&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>21.1. Weitere Präsensstämme auf -nt <ul><li>21.1.1. Partizip Präsens (लडादेशः) Parasmaipada</li><li>21.1.2. महान्त् &quot;groß&quot;</li></ul></li><li>21.2. Sandhi für auslautende Nasale</li><li>21.3. Höfliche Formen der Anrede</li><li>21.4. Wortliste</li><li>21.5. Übung</li></ul><h2 id="_21-1-weitere-prasensstamme-auf-nt" tabindex="-1">21.1. Weitere Präsensstämme auf -nt <a class="header-anchor" href="#_21-1-weitere-prasensstamme-auf-nt" aria-label="Permalink to &quot;21.1. Weitere Präsensstämme auf -nt&quot;">​</a></h2><h3 id="_21-1-1-partizip-prasens-लडादेशः-parasmaipada" tabindex="-1">21.1.1. Partizip Präsens (लडादेशः) Parasmaipada <a class="header-anchor" href="#_21-1-1-partizip-prasens-लडादेशः-parasmaipada" aria-label="Permalink to &quot;21.1.1. Partizip Präsens (लडादेशः) Parasmaipada&quot;">​</a></h3><p>Dieses Partizip ist eine Nominalbildung aus dem Präsensstamm, also ein echtes Partizip. Es ist ein Adjektiv, das angibt, dass jemand oder etwas das durch die Verbalwurzel (+ Präverb) Ausgedrückte gerade tut, während etwas anderes geschieht. Auch ein dauernder Zustand kann damit ausgedrückt werden.</p><p>Beispiele:</p><blockquote><p>&quot;Während Vater liest, raucht er = der lesende Vater raucht&quot;<br> &quot;ein seiender (= wirklicher, echter) Freund&quot;</p></blockquote><table><tbody><tr><td colspan="3">**Bildung des Partizip Präsens Parasmaipada zu thematischen Präsensstämmen:** </td></tr><tr><td>**Maskulinum, Neutrum**</td><td></td><td></td></tr><tr><td></td><td>**starker Stamm**</td><td>**Präsensstamm + -nt-**</td></tr><tr><td></td><td>**schwacher Stamm**</td><td>**Präsensstamm + -t-**</td></tr><tr><td>**Femininum**</td><td></td><td></td></tr><tr><td></td><td></td><td>**Präsensstamm + -nt- + -ī (Deklination wie देवी)**</td></tr><tr><td></td><td>**6. Präsensklasse**</td><td>**Präsensstamm + -nt- + -ī****oder:**<br>**Präsensstamm + -t- + -ī**</td></tr></tbody></table><p>Beispiele:</p><p>1. Präsensklasse:</p><blockquote><p>यजब्त् &quot;ein mit einem Opfer verehrender&quot;</p><p>|   |   | Maskulinum<br> पुंस् | Neutrum<br> नपुंसक | Femininum<br> स्त्री | | --- | --- | --- | --- | --- | | Singular<br> एकवचन | 1. Nominativ<br> प्रथमा | यजन्<br> aus yaja-nt-s | यजत्<br> yaja-t-Ø | यजन्ती<br> yaja-ant-ī | |   | 2. Akkusativ<br> द्वितीया | यजन्तम्<br> yaja-nt-am | यजत् | wie देवी | |   | 3. Instrumentalis<br> तृतीया | यजता<br> yaja-t-ā | यजता |   | |   | 6. Genetiv<br> षष्ठी | यजतस्<br> yaja-t-as | यजतस् |   | | Plural<br> बहुवचन | 1. Nominativ<br> प्रथमा | यजन्तस्<br> yaja-nt-as | यजन्ति<br> yaja-nt-i<br> Beachten Sie den Gleichlaut mit der 3. pl. P.! |   | |   | 2. Akkusativ<br> द्वितीया | यजतस्<br> yaja-t-as | यजन्ति |   | |   | 3. Instrumentalis<br> तृतीया | यजद्भिस्<br> aus yaja-t-bhis | यजद्भिस् |   | |   | 6. Genetiv<br> षष्ठी | यजताम्<br> yaja-t-ām | यजताम् |   |</p></blockquote><p>4. Präsensklasse</p><blockquote><p>नृत्यन्त् &quot;tanzend&quot;</p><ul><li>Maskulinum Nom. sg. नृत्यन्</li><li>Neutrum Nom. Akk. sg. नृत्यत्</li><li>Femininum Nom. sg. नृत्यन्ती</li></ul></blockquote><p>6. Präsensklasse</p><blockquote><p>विशन्त् &quot;eintretend&quot;</p><ul><li>Maskulinum Nom. sg. विशन्</li><li>Neutrum Nom. Akk. sg. विशत्</li><li>Femininum Nom. sg. विशन्ती । विशती</li></ul></blockquote><table><tbody><tr><td colspan="3">**Bildung des Partizip Präsens Parasmaipada zu athematischen Präsensstämmen (außer 3. Präsensklasse):** </td></tr><tr><td>**Maskulinum, Neutrum**</td><td></td><td></td></tr><tr><td></td><td>**starker Stamm**</td><td>**Präsensstamm + -ant-**</td></tr><tr><td></td><td>**schwacher Stamm**</td><td>**Präsensstamm + -at-****Der Auslaut des schwachen Präsensstammes lautet gleich wie vor der 3. Plur. P**</td></tr><tr><td>**Femininum**</td><td></td><td></td></tr><tr><td></td><td></td><td>**Präsensstamm + -at- + -ī (Deklination wie देवी)**</td></tr></tbody></table><p>Beispiele:</p><p>2. Präsensklasse:</p><blockquote><p>अस् &quot;sein&quot;: सन्त् &quot;seiend, echter, guter, wahrer&quot;</p><p>|   |   | Maskulinum<br> पुंस् | Neutrum<br> नपुंसक | Femininum<br> स्त्री | | --- | --- | --- | --- | --- | | Singular<br> एकवचन | 1. Nominativ<br> प्रथमा | सन्<br> aus s-ant-s | सत्<br> s-at-Ø | सती1<br> s-at-ī | |   | 2. Akkusativ<br> द्वितीया | सन्तम्<br> s-ant-am | सत् | wie देवी | |   | 3. Instrumentalis<br> तृतीया | सता<br> s-at-ā | सता |   | |   | 6. Genetiv<br> षष्ठी | सतस्<br> s-at-as | सतस् |   | | Plural<br> बहुवचन | 1. Nominativ<br> प्रथमा | सन्तस्<br> s-ant-as | सन्ति<br> s-ant-i |   | |   | 2. Akkusativ<br> द्वितीया | सतस्<br> s-at-as | सन्ति |   | |   | 3. Instrumentalis<br> तृतीया | सद्भिस्<br> aus s-at-bhis | सद्भिस् |   | |   | 6. Genetiv<br> षष्ठी | सताम्<br> s-at-ām | सताम् |   |</p><p>1 सती &quot;eine gute (treue) Frau (die sich in späterer Zeit nach dem Tod ihres Mannes mit diesem verbrennen lässt)&quot; engl.: sutee</p></blockquote><p><img src="'+n+'" alt=""><br> Abb.: सती-Gedenkplatte im Palast von Jodhpur - जोधपुर / Rajasthan - राजस्थान<br> [Bildquelle: Flicka / Wikipedia. GNU FDLicense]</p><p>5. Präsensklasse:</p><blockquote><p>सु &quot;pressen&quot; सुन्वन्त्</p><ul><li>Maskulinum Nom. sg. सुन्वन्</li><li>Neutrum Nom. Akk. sg. सुन्वत्</li><li>Femininum Nom. sg. सुन्वती</li></ul></blockquote><p>8. Präsensklasse</p><blockquote><p>कृ &quot;tun&quot;: कुर्वन्त्</p><ul><li>Maskulinum Nom. sg. कुर्वन्</li><li>Neutrum Nom. Akk. sg. कुर्वत्</li><li>Femininum Nom. sg. कुर्वती</li></ul></blockquote><h3 id="_21-1-2-महान्त्-groß" tabindex="-1">21.1.2. महान्त् &quot;groß&quot; <a class="header-anchor" href="#_21-1-2-महान्त्-groß" aria-label="Permalink to &quot;21.1.2. महान्त् &quot;groß&quot;&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Maskulinum, Neutrum</th><th></th><th></th></tr></thead><tbody><tr><td></td><td>starker Stamm</td><td>महान्त्</td></tr><tr><td></td><td>schwacher Stamm</td><td>महत्</td></tr><tr><td>Femininum</td><td></td><td></td></tr><tr><td></td><td></td><td>महती</td></tr><tr><td>wie देवी</td><td></td><td></td></tr></tbody></table><p>|   |   | Maskulinum<br> पुंस् | Neutrum<br> नपुंसक | Femininum<br> स्त्री | | --- | --- | --- | --- | --- | | Singular<br> एकवचन | 1. Nominativ<br> प्रथमा | महान्<br> aus mahānt-s | महत्<br> mahat-Ø | महती<br> mahat-ī | |   | 2. Akkusativ<br> द्वितीया | महान्तम्<br> mahānt-am | महत् | wie देवी | |   | 3. Instrumentalis<br> तृतीया | महता<br> mahat-ā | महता |   | |   | 6. Genetiv<br> षष्ठी | महतस्<br> mahat-as | महतस् |   | | Plural<br> बहुवचन | 1. Nominativ<br> प्रथमा | महान्तस्<br> mahānt-as | महान्ति<br> mahānt-i |   | |   | 2. Akkusativ<br> द्वितीया | महतस्<br> mahat-as | महान्ति |   | |   | 3. Instrumentalis<br> तृतीया | महद्भिस्<br> aus mahat-bhis | महद्भिस् |   | |   | 6. Genetiv<br> षष्ठी | महताम्<br> mahat-ām | महताम् |   |</p><p>Als Vorderglied eines Kompisitums steht statt महत् महा:</p><p>z.B.</p><blockquote><p>महादेव &quot;der große Gott&quot; (z.B. शिव)</p><p>महादेवी &quot;die große Göttin, die Hauptfrau eines Königs (देव)&quot;</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: महादेवो विष्णुः<br> [Bildquelle: PHGCOM / Wikipedia. GNU FDLicense]</p><blockquote><p>&quot;A 4th-6th century CE Sardonyx seal representing Vishnu with a worshipper. The inscription in cursive Bactrian reads: &quot;Mihira, Vishnu and Shiva&quot;.</p></blockquote><h2 id="_21-2-sandhi-fur-auslautende-nasale" tabindex="-1">21.2. Sandhi für auslautende Nasale <a class="header-anchor" href="#_21-2-sandhi-fur-auslautende-nasale" aria-label="Permalink to &quot;21.2. Sandhi für auslautende Nasale&quot;">​</a></h2><p>Nach kurzem Vokal werden auslautende Nasale - außer -m - vor anlautendem Vokal verdoppelt.</p><p>z.B.</p><blockquote><p>जयन् + अरिः » जयन्नरिः &quot;der siegende Feind&quot;</p></blockquote><h2 id="_21-3-hofliche-formen-der-anrede" tabindex="-1">21.3. Höfliche Formen der Anrede <a class="header-anchor" href="#_21-3-hofliche-formen-der-anrede" aria-label="Permalink to &quot;21.3. Höfliche Formen der Anrede&quot;">​</a></h2><p>Man kann im Sanskrit, ohne unhöflich zu sein, jemanden in der 2. Person Singular ansprechen. Will man aber höflich sein, kann man ein Nomen verwenden, dessen Bedeutung &quot;Ehrwürdiger&quot; und dergleichen ist, und das Verb in die 3. Person sg. oder pl. setzen bzw. eine Passivkonstruktion verwenden. Die Steigerung der Höflichkeit im Gebrauch der Person bei der Anrede ist etwa folgende:</p><p>2. sg. » 2. pl. » 3. sg. mit entsprechendem Nomen » 3. pl. mit entspr. Nomen</p><p>Das wichtigste solche Höflichkeitsnomen ist भवन्त् , fem.: भवती . Es entspricht in seiner Verwendung unserem höflichen &quot;Sie&quot;.</p><p>Dieses भवन्त् ist eine Zusammenziehung aus भगवन्त्, seine Deklination ist die der Nomina auf -vant (siehe <a href="./lektion13">Lektion 13</a>). Dieses भवन्त् ist zu unterscheiden vom Partizip Präsens P von भू &quot;werden&quot; भवन्त् : der Nom sg. mask. von भवन्त् &quot;Sie&quot; lautet भवान्, der des Partizips भवन्.</p><p>Beispiele:</p><blockquote><p>किं भवान्करोति = किं भवता क्रियते = &quot;Was tun Sie?&quot;</p></blockquote><p>höflicher:</p><blockquote><p>किं भवन्तः कुर्वन्ति = किं भवद्भिः क्रियते</p></blockquote><p>Femininum:</p><blockquote><p>किं भवती करोति = किं भव्त्या क्रियते</p><p>किं भवत्यः कुर्वन्ति = किं भवतीभिः क्रियते</p></blockquote><p>Weitere Wörter, die ähnlich wie भवन्त् verwendet werden können:</p><ul><li><p>आर्य (f.: आर्या)  &quot;Edler&quot;. z.B. यदार्य इच्छति &quot;Was Sie wünschen&quot;</p></li><li><p>महाभाग &quot;der dessen Anteil / Glück groß ist = Vornehmer&quot;. Oft verwendet von Frauen bei der Anrede oder beim Sprechen über Männer von gutem Stand. In modernem gesprochenem Sanskrit sehr häufig.</p></li></ul><p>Will man nicht nur Höflichkeit, sondern auch Verehrung für jemanden ausdrücken, verwendet man bei jemandem, der anwesend oder in der Nähe ist, anstelle von भवन्त् अत्रभवन्त् , für jemanden Abwesenden oder Entfernten तत्रभवन्त्. अत्रभवन्त् und तत्रभवन्त् kann man mit &quot;Sie&quot;, &quot;Ehrwürden&quot;, &quot;Hochwürden&quot; usw. übersetzen:</p><blockquote><p>किमत्रभवत्यत्रभवतां भार्या = &quot;Ist die gnädige (hier anwesende) Frau Ihre Gattin?&quot;</p><p>किं तत्रभवतां कुशलवृत्तम् (in einem Brief oder Telefongespräch) = &quot;Geh es Ihnen gut?&quot;</p></blockquote><h2 id="_21-4-wortliste" tabindex="-1">21.4. Wortliste <a class="header-anchor" href="#_21-4-wortliste" aria-label="Permalink to &quot;21.4. Wortliste&quot;">​</a></h2><p>भज् 1 U भजति Pass. भज्यते PPP भक्त : jemandem (Akk.) etwas zuteilen, zukommen lassen, jemanden lieben, ehren, verehren</p><p>davon:</p><blockquote><p>भक्ति f.: Ergebenheit, Treue, Liebe (im religiösen Bereich: Liebe und Respekt zu einem persönlichen Gott. siehe dazu Basham, Wonder S. 332f.)</p><p>भाग m.: Anteil, Teil</p><p>भग m.: (guter) Anteil, Glück, Wohlergehen, Würde</p><p>भगवन्त् 3: Glück-besitzend, Würde-besitzend (Beiname von विष्णु - कृष्ण)</p></blockquote><p><img src="'+o+'" alt=""><br> Abb.: भगवान्कृष्णः als जगन्नाथ (rechts) mit seiner Halbschwester सुभद्रा (Mitte) und seinem älteren Bruder बलराम<br> Orissa = ଓଡ଼ିଶା<br> [Bildquelle: Sujitkumar / Wikipedia. GNU FDLicense]</p><blockquote><p>भगवद्गीता f.: &quot;Gesang (गीता) des Würdigen (कृष्ण)&quot;</p><p><img src="'+u+'" alt=""><br> Abb.: भगवद्गीता - Manuskript, 19. Jhdt.<br> [Bildquelle: Wikipedia, Public domain]</p><p>भिक्ष् 1 Ā भिक्षते Pass. भिक्ष्यते PPP भिक्षित (eigentlich ein Desiderativum zu भज्: wünschen, dass man teilhat): betteln</p><p>davon:</p><blockquote><p>भिक्षु m.: Bettler, Mönch</p></blockquote></blockquote><p><img src="'+l+'" alt=""><br> Abb.: भिक्षवः<br> Luang Prabang = ຫລວງພະບາງ, Laos = ປະເທດລາວ<br> [Bildquelle: Hanoi Mark. -- <a href="http://www.flickr.com/photos/riverdaleto/112938743/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/riverdaleto/112938743/</a>. -- Zugriff am 2008-12-12. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><p>दुष् 4 P दुष्यति Pass. दुष्यते PPP दुष्ट : verderben (intransitiv), schlecht werden, zuschande werden</p><blockquote><p>दोष m.: Fehler</p></blockquote><p>पच् 1 U पचति Pass. पच्यते (kein PPP, dafür पक्व 3: gekocht, gegart) Absol. पक्त्वा : garen (transitiv) = kochen, braten, rösten usw.</p><h2 id="_21-5-ubung" tabindex="-1">21.5. Übung <a class="header-anchor" href="#_21-5-ubung" aria-label="Permalink to &quot;21.5. Übung&quot;">​</a></h2><p>A) Übersetzen Sie folgende Komposita:</p><p>१. अनादिकालिकसंसरः</p><p>२. अनादिमध्यान्तः</p><p>३. महामैत्रीकरुणाचित्तः</p><p>४. सर्वहतान्धकारः</p><p>B) Übersetzen Sie:</p><p>मृतं दहन्नग्निः सतीमपि दहति ॥१॥</p><p>सद्गुरुर्महाकविस्तोत्रैर्महादेवं स्तौति ॥२॥</p><p>महान्ति फलान्यदन्तो बाला जलमापि पिबन्ति ॥३॥</p><p>पुजां कुर्वञ्जनो यजते च स्तौति च देवताम् ॥४॥</p><p>गुरूपनीतनरो द्विजः ॥५॥</p><p>जितक्रोधो घ्नन्तमप्यरिं न द्वेष्टि । क्रोधजितस्तु द्वेष्टि ॥६॥</p>',76)])])}const P=t(d,[["render",m]]);export{g as __pageData,P as default};
